head.b:skin:
/* ============================================
   XTOX BLOGGER THEME — Dark Professional
   Brand: #6366f1 (indigo) / #8b5cf6 (violet)
   BG: #0f0f1a / Surface: #1a1a2e
============================================ */

* { box-sizing: border-box; margin: 0; padding: 0; }

body {
  font-family: 'Segoe UI', 'Tahoma', Arial, sans-serif;
  background: #0f0f1a;
  color: #e2e8f0;
  direction: rtl;
  min-height: 100vh;
}

/* ---- HEADER ---- */
#header-wrapper {
  background: linear-gradient(135deg, #1e1b4b 0%, #312e81 100%);
  border-bottom: 1px solid rgba(99,102,241,0.3);
  position: sticky;
  top: 0;
  z-index: 100;
  box-shadow: 0 4px 24px rgba(0,0,0,0.4);
}

#header {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 64px;
}

#header h1 {
  font-size: 28px;
  font-weight: 900;
  color: #fff;
  letter-spacing: -1px;
}

#header h1 a {
  color: #fff;
  text-decoration: none;
  display: flex;
  align-items: center;
  gap: 10px;
}

#header h1 a::before {
  content: '🦊';
  font-size: 24px;
}

.header-cta {
  background: linear-gradient(135deg, #6366f1, #8b5cf6);
  color: #fff !important;
  text-decoration: none !important;
  padding: 8px 20px;
  border-radius: 50px;
  font-weight: bold;
  font-size: 14px;
  white-space: nowrap;
}

/* ---- NAV ---- */
#nav-wrapper {
  background: rgba(26,26,46,0.95);
  border-bottom: 1px solid rgba(99,102,241,0.15);
}

#nav {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
  display: flex;
  gap: 0;
  overflow-x: auto;
  scrollbar-width: none;
}

#nav a {
  color: #a5b4fc;
  text-decoration: none;
  padding: 12px 16px;
  white-space: nowrap;
  font-size: 14px;
  font-weight: 500;
  border-bottom: 2px solid transparent;
  transition: all 0.2s;
}

#nav a:hover {
  color: #fff;
  border-bottom-color: #6366f1;
}

/* ---- LAYOUT ---- */
#outer-wrapper {
  max-width: 1200px;
  margin: 0 auto;
  padding: 24px 20px;
  display: grid;
  grid-template-columns: 1fr 300px;
  gap: 24px;
}

/* ---- POST CARDS ---- */
.blog-posts { }

.post-outer {
  background: #1a1a2e;
  border: 1px solid rgba(99,102,241,0.2);
  border-radius: 16px;
  margin-bottom: 20px;
  overflow: hidden;
  transition: border-color 0.2s, transform 0.2s;
}

.post-outer:hover {
  border-color: rgba(99,102,241,0.5);
  transform: translateY(-2px);
}

.post-thumbnail {
  width: 100%;
  height: 240px;
  object-fit: cover;
  display: block;
}

.post-body {
  padding: 20px;
}

h3.post-title {
  font-size: 20px;
  font-weight: 700;
  color: #fff;
  margin-bottom: 8px;
  line-height: 1.4;
}

h3.post-title a {
  color: #fff;
  text-decoration: none;
}

h3.post-title a:hover { color: #a5b4fc; }

.post-labels {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-bottom: 12px;
}

.post-labels a {
  background: rgba(99,102,241,0.15);
  color: #a5b4fc;
  text-decoration: none;
  padding: 3px 10px;
  border-radius: 20px;
  font-size: 12px;
  border: 1px solid rgba(99,102,241,0.3);
}

.post-snippet {
  color: #94a3b8;
  font-size: 14px;
  line-height: 1.6;
  margin-bottom: 16px;
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.read-more-link {
  display: inline-block;
  background: linear-gradient(135deg, #6366f1, #8b5cf6);
  color: #fff;
  text-decoration: none;
  padding: 10px 24px;
  border-radius: 50px;
  font-size: 14px;
  font-weight: bold;
}

/* ---- SIDEBAR ---- */
#sidebar-wrapper { }

.sidebar-widget {
  background: #1a1a2e;
  border: 1px solid rgba(99,102,241,0.2);
  border-radius: 16px;
  padding: 20px;
  margin-bottom: 20px;
}

.sidebar-widget h2 {
  color: #a5b4fc;
  font-size: 16px;
  font-weight: 700;
  margin-bottom: 16px;
  padding-bottom: 10px;
  border-bottom: 1px solid rgba(99,102,241,0.2);
}

.app-download-card {
  background: linear-gradient(135deg, #1e1b4b, #312e81);
  border: 1px solid rgba(99,102,241,0.4);
  border-radius: 16px;
  padding: 24px;
  text-align: center;
  margin-bottom: 20px;
}

.app-download-card h2 {
  color: #fff;
  font-size: 20px;
  margin-bottom: 8px;
  border: none;
  padding: 0;
}

.app-download-card p {
  color: #a5b4fc;
  font-size: 13px;
  margin-bottom: 16px;
}

.app-download-btn {
  display: block;
  background: linear-gradient(135deg, #6366f1, #8b5cf6);
  color: #fff;
  text-decoration: none;
  padding: 12px 24px;
  border-radius: 50px;
  font-weight: bold;
  font-size: 15px;
}

/* ---- INDIVIDUAL POST PAGE ---- */
.post-body-content {
  background: #1a1a2e;
  border-radius: 16px;
  padding: 24px;
  border: 1px solid rgba(99,102,241,0.2);
}

/* ---- FOOTER ---- */
#footer-wrapper {
  background: #1a1a2e;
  border-top: 1px solid rgba(99,102,241,0.2);
  margin-top: 48px;
}

#footer {
  max-width: 1200px;
  margin: 0 auto;
  padding: 32px 20px;
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 32px;
}

.footer-col h4 { color: #a5b4fc; margin-bottom: 12px; font-size: 14px; }
.footer-col a { display: block; color: #6b7280; text-decoration: none; margin-bottom: 8px; font-size: 13px; }
.footer-col a:hover { color: #e2e8f0; }
.footer-col p { color: #6b7280; font-size: 13px; line-height: 1.8; }

.footer-bottom {
  text-align: center;
  padding: 16px 20px;
  color: #4b5563;
  font-size: 12px;
  border-top: 1px solid rgba(99,102,241,0.1);
}

/* ---- RESPONSIVE ---- */
@media (max-width: 768px) {
  #outer-wrapper {
    grid-template-columns: 1fr;
  }
  #sidebar-wrapper { order: -1; }
  #footer { grid-template-columns: 1fr; }
  .post-thumbnail { height: 180px; }
  #header h1 { font-size: 20px; }
}

/* ---- SEARCH ---- */
.search-form {
  display: flex;
  gap: 8px;
  margin-bottom: 20px;
}

.search-form input {
  flex: 1;
  background: #1a1a2e;
  border: 1px solid rgba(99,102,241,0.3);
  border-radius: 50px;
  padding: 10px 18px;
  color: #e2e8f0;
  font-size: 14px;
  outline: none;
  direction: rtl;
}

.search-form input:focus { border-color: #6366f1; }

.search-form button {
  background: #6366f1;
  color: #fff;
  border: none;
  border-radius: 50px;
  padding: 10px 20px;
  cursor: pointer;
  font-weight: bold;
  font-size: 14px;
}

/* ---- PAGER ---- */
.blog-pager {
  display: flex;
  justify-content: space-between;
  margin-top: 24px;
}

.blog-pager a {
  background: rgba(99,102,241,0.15);
  color: #a5b4fc;
  text-decoration: none;
  padding: 10px 20px;
  border-radius: 50px;
  font-size: 14px;
  border: 1px solid rgba(99,102,241,0.3);
}

.blog-pager a:hover { background: rgba(99,102,241,0.3); }

/* ---- STAT BADGES ---- */
.stat-badge {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  background: rgba(99,102,241,0.1);
  color: #a5b4fc;
  padding: 3px 10px;
  border-radius: 20px;
  font-size: 12px;
  margin-left: 6px;
}

body.script:
{
  "@context": "https://schema.org",
  "@type": "WebSite",
  "name": "XTOX — سوق عربي",
  "url": "https://xt0x.blogspot.com",
  "description": "السوق المحلي العربي الذكي — بيع واشترِ بكل سهولة",
  "inLanguage": "ar",
  "potentialAction": {
    "@type": "SearchAction",
    "target": "https://xt0x.blogspot.com/search?q={search_term_string}",
    "query-input": "required name=search_term_string"
  }
}
